#include <iostream>
using namespace std;

// Define the structure for a tree node
struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int node_value) {
        val = node_value;
        left = right = NULL;
    }
};

// Function to check if two trees are identical
bool areIdenticalTrees(Node* p, Node* q) {
    // If both nodes are NULL, they are identical
    if (p == NULL && q == NULL)
        return true;
    // If only one of the nodes is NULL, they are not identical
    if (p == NULL || q == NULL)
        return false;
    // Check if values are equal and recursively check left and right subtrees
    if (p->val == q->val)
        return areIdenticalTrees(p->left, q->left) &&
               areIdenticalTrees(p->right, q->right);
    // Values are not equal, they are not identical
    return false;
}

int main() {
    int N, M;
    cin >> N >> M;
    Node* root1 = new Node(1);
    Node* root2 = new Node(1);
    // ... create the rest of the trees
    bool result = areIdenticalTrees(root1, root2);
    if (result)
        cout << "YES";
    else
        cout << "NO";
    return 0;
}

